drop database if exists landmarks;
create database if not exists landmarks;
use landmarks;

create table list_landmarks (
	id int auto_increment primary key,
    name varchar(255) not null,
    city varchar(255) not null,
    manicipality varchar(255) not null,
    type varchar(255) not null,
    description text,
	image_path varchar(855),
    location varchar(555) not null
);

insert into list_landmarks (name, city, manicipality, type, description, image_path, location)
values ('Къщата музей „Никола Вапцаров"', 'Банско', 'Благоевград', 'Музей', 'Музеят има три функционални части – 
видеозала в две помещения, където е изложено родословното му дърво, автентична етнографска експозиция за целия му 
живот от раждането до смъртта и отделна видеозала – поезията на Вапцаров. Тук са изложени и копия от негови ръкописи, 
първите публикации на неговите стихове, събрани по-късно в отделна стихосбирка. Във витрина се пазят костюмът, ризата и 
часовникът, носени от поета преди разстрела. Във фонда на музея има около 3000 експоната.', 
'https://upload.wikimedia.org/wikipedia/commons/thumb/5/50/House-museum_of_Nikola_Vaptsarov_svik.JPG/1280px-House-museum_of_Nikola_Vaptsarov_svik.JPG',
'https://maps.app.goo.gl/nLPXiLTgU2xTCTkf6'),
('Църква „Света Троица“', 'Банско', 'Благоевград', 'Православна църква', 'Църквата „Света Троица“ е изградена в центъра на селото 
от местни строители през 1835 година, благодарение на общите усилия и щедрост на банскалии. Мястото за строене на църквата е дарено – 
най-голям дарител е Лазар Герман – заможен банскалия и кмет на българската община.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/6/60/Sveta_troica_bansko.jpg/1280px-Sveta_troica_bansko.jpg',
'https://maps.app.goo.gl/xZ9FjPxJ83XHZR8N7'),
('Църква „Св. св. Теодор Тирон и Теодор Стратилат“', 'с. Добърско', 'Благоевград', 'Православна църква', '„Св. св. Теодор Тирон и Теодор Стратилат“ 
е православна църква от 1614 година, разположена в разложкото село Добърско, България. Църквата, в която има запазени изключително ценни стенописи, 
е национален паметник на културата.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/54/Sts._Theodore_Tyron_%26_Theodore_Stratelates%2C_Dobarsko_2021_03.jpg/375px-Sts._Theodore_Tyron_%26_Theodore_Stratelates%2C_Dobarsko_2021_03.jpg',
'https://maps.app.goo.gl/z9Cqkwrmhf1rSKnR7'),
('Музей за историята на град Мелник', 'Мелник', 'Благоевград', 'Музей', 'Музеят има етнографска експозиция, свързана с бита, културата и основния 
поминък на българите от Пиринска Македония – винарството. Изложени са находки от региона, датирани към всички епохи от праисторията до новото време. 
В богата експозиция е представен градският тип култура и бит на гръцките фамилии в Мелник през Възраждането.',
'https://th.bing.com/th/id/R.c25b3aa887de6305f14642d4cbd00eaf?rik=GvB2yLdjjxeOlA&pid=ImgRaw&r=0&sres=1&sresct=1',
'https://maps.app.goo.gl/XtYRe4Ay3wgkKFyv5'),
('Роженският манастир „Рождество Богородично“', 'с. Рожен', 'Благоевград', 'Манастир', 'Роженският манастир „Рождество Богородично“ е средновековен манастир, 
най-големият в Пиринска Македония, България. В миналото манастирът е бил ставропигиален, а днес е подчинен на Неврокопската епархия на Българската православна църква. 
Манастирът е обявен в 1973 година за паметник на културата с национално значение.',
'https://upload.wikimedia.org/wikipedia/commons/c/cf/Bulgarien-Roschen-2-1996.jpg',
'https://maps.app.goo.gl/2PpCLzjsZPYGZmpQA'),
('Местност „Рупите“ – храм „Света Петка Българска“', 'Петрич', 'Благоевград', 'Местност', 'Построен е през 1994 година по проект на архитектите Богдан Томалевски и 
Лозан Лозанов и изписан от художника Светлин Русев. Строител на храма е инженер Кочо Ангов. Кръстът над църквата е дело на скулптора Крум Дамянов.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/6/67/Rupite_Church_St._Petka_Bulgarska.JPG/1280px-Rupite_Church_St._Petka_Bulgarska.JPG',
'https://maps.app.goo.gl/r3SNETbexwGh3ZCo8'),
('Самуилова крепост', 'Петрич', 'Благоевград', 'Крепост', 'Намира се на невисокия хълм Куфалница, разположен на десния бряг на река Струмешница, на 5 километра 
северно от село Ключ. Построена е вероятно в периода 1009 – 1013 година по време на управлението на цар Самуил и е част от мащабна фортификационна система.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/2/25/Samuil-fortress-bg-tower.jpg/1280px-Samuil-fortress-bg-tower.jpg',
'https://maps.app.goo.gl/RfdAiKjtB3sRvpBa8'),
('Античен град „Хераклея Синтика“', 'Петрич', 'Благоевград', 'Античен град', 'Хераклея Синтика е античен град в днешна Югозападна България. Руините му са разположени 
в землището на село Рупите, община Петрич, върху южния склон и подножието на Джонков връх, който е част от вулканичното възвишение Кожух.',
'https://upload.wikimedia.org/wikipedia/commons/b/bb/Bulgaria_Blagoevgrad_Province_relief_location_map.jpg',
'https://maps.app.goo.gl/tUj8sfN4XwbJdRo86'),
('Музей „Старинен Несебър“', 'Несебър', 'Бургас', 'Музей', 'Създаден е през 1956 г. и първата му експозиция е уредена в църквата „Свети Йоан Кръстител“.
В новата си сграда, строена специално за музей по проект на арх. Христо Коев, се премества през 1994 г. и голяма част от експонатите са включени в неговата експозиция, 
обхващаща фоайе и 4 зали.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/44/Nessebur_Museum.JPG/1280px-Nessebur_Museum.JPG',
'https://maps.app.goo.gl/85J9347FY7786S7L9'),
('Музей на солта', 'Поморие', 'Бургас', 'Музей', 'Музеят се състои от експозиционна зала и 20 декара солници на открито, където и до днес се добива сол. 
Солниците към музея произвеждат сол по същия начин, както това е ставало в древността. Намира се в самия град Поморие, на брега на Поморийско езеро.',
'https://upload.wikimedia.org/wikipedia/commons/2/22/Solnici.jpg',
'https://maps.app.goo.gl/mkWg47reKygXK2Zc9'),
('Римските терми', 'Варна', 'Варна', 'Паметник', 'Те са сред най-запазените архитектурни паметници от античния период в България. Изградени са през Римската епоха, 
към края на II век и представляват най-голямата римска баня на Балканите. Според проучванията височината на сводестите конструкции е била над 20 м, а общата площ на 
съоръжението около 7000 m². Баните са функционирали до края на III век.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/44/Odesos-thermae-in-Varna.jpg/375px-Odesos-thermae-in-Varna.jpg',
'https://maps.app.goo.gl/oetab4yekdGLudacA'),
('Паркът музей „Владислав Варненчик“', 'Варна', 'Варна', 'Музей', 'Паркът музей „Владислав Варненчик“ във Варна е създаден през 1924 г. като лобно място на загиналите воини при битката при Варна, 
състояла се през 1444 г. Тогава полско-литовско-унгарският крал Владислав III води кръстоносен поход срещу нахлуващите турци на Балканския полуостров.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/3/39/VarnaMemorial.jpg/375px-VarnaMemorial.jpg',
'https://maps.app.goo.gl/PBeacLNWYQcc6Yoh7'),
('Аладжа манастир', 'Варна', 'Варна', 'Манастир', 'Аладжа манастир е средновековен скален манастир в България. Манастирските пещери са изсечени в 25-метрова отвесна карстова скала 
в близост до горния край на Франгенското плато на няколко нива. Комплексът включва две малки близки катакомби.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e4/Monasterio_de_Aladzha%2C_provincia_de_Varna%2C_Bulgaria%2C_2016-05-27%2C_DD_122.jpg/375px-Monasterio_de_Aladzha%2C_provincia_de_Varna%2C_Bulgaria%2C_2016-05-27%2C_DD_122.jpg',
'https://maps.app.goo.gl/Ey5rLJ1HHJzjpscb9'),
('Къща музей „Иларион Макариополски“', 'Елена', 'Велико Търново', 'Музей', 'Къщата музей „Иларион Макариополски“ се намира в град Елена. От всички запазени стари къщи в Елена най-интересна е къщата музей „Иларион Макариополски“. Тя е паметник на културата с национално значение. В нея са се родили борецът за църковна независимост Иларион Макариополски, брат му Никола Михайловски, който е виден книжовен и просветен възрожденски деец и неговият син поетът сатирик Стоян Михайловски. В една от стаите през 1863 година е основано еленското читалище „Напредък“.',
'https://live.staticflickr.com/65535/49403045156_150a55b99a_z.jpg', 'https://maps.app.goo.gl/Avrh2p3LEgbWbSkN9'),
('Архитектурно-исторически резерват „Царевец“', 'Велико Търново', 'Велико Търново', 'Архитектурно-исторически резерват', 'Царевец е хълм във Велико Търново, както и едноименна крепост в средновековния Търновград.
Разположена е в близост до стария град на Велико Търново. Тя е била главната българска крепост по време на Второто българско царство (1185 – 1396), когато Търново е столица на царството. През Средновековието хълмът, 
на който се намира, е изцяло застроен с жилищни и административни постройки.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a7/Tsarevets_Fortress%2C_Veliko_Tarnovo_-_3_March_2021%2C_rk.aerial.jpg/1200px-Tsarevets_Fortress%2C_Veliko_Tarnovo_-_3_March_2021%2C_rk.aerial.jpg',
'https://maps.app.goo.gl/cxwSepnDxt9yzAHYA'),
('Древен град Никополис ад Иструм', 'с. Никюп', 'Велико Търново', 'Древен град', 'Руините му са достъпни за посещение от ранна пролет до късна есен. Античният град се намира на левия бряг на река Росица веднага 
вляво след моста на пътя Велико Търново – Русе. Никополис ад Иструм се проучва от археолозите още от 1900 г. Основан е през 102 г. от император Траян в чест на римската победа над даките.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b7/Nikopolis_ad_Istrum_view_1.jpg/1280px-Nikopolis_ad_Istrum_view_1.jpg', 'https://maps.app.goo.gl/TmeSVSphF61oP3GZA'),
('Къщата музей „Алеко Константинов“', 'Свищов', 'Велико Търново', 'Музей', 'Тя е създадена като музей през 1926 г. Още приживе големият български писател подарява родната си къща на Свищовската община, 
за да се използва за културните нужди на града. От 1979 г. домът на писателя хуморист Ал. Константинов става мемориален музей.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b8/%D0%9A%D1%8A%D1%89%D0%B0_%D0%BC%D1%83%D0%B7%D0%B5%D0%B9_%D0%90%D0%BB%D0%B5%D0%BA%D0%BE_%D0%9A%D0%BE%D0%BD%D1%81%D1%82%D0%B0%D0%BD%D1%82%D0%B8%D0%BD%D0%BE%D0%B2.jpg/1280px-%D0%9A%D1%8A%D1%89%D0%B0_%D0%BC%D1%83%D0%B7%D0%B5%D0%B9_%D0%90%D0%BB%D0%B5%D0%BA%D0%BE_%D0%9A%D0%BE%D0%BD%D1%81%D1%82%D0%B0%D0%BD%D1%82%D0%B8%D0%BD%D0%BE%D0%B2.jpg',
'https://maps.app.goo.gl/dW8hPhiUeCLKUUGg7'),
('Музей-крепост „Баба Вида“', 'Видин', 'Видин', 'Музей-крепост', '„Баба Вида“, наричан и „Бабини Видини кули“ (и двете са жаргонни названия), е средновековен замък в старопрестолния град Видин. 
Това е за единственият изцяло запазен замък в България. Служил е за резиденция на видинските царе през Средновековието (с казарма за охранителите и други служебни помещения), както и за оръжеен склад и затвор в края на османското управление.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/e/ed/Baba_Vida_Klearchos_1.jpg/1200px-Baba_Vida_Klearchos_1.jpg',
'https://maps.app.goo.gl/Jy3odFZN7gA1cQsm8'),
('Музей „Конака“', 'Видин', 'Видин', 'Музей', 'Създаден е като археологическо дружество през 1910 г. Според устава му неговата цел е „да се издирват, съхраняват и изучават паметниците на миналото, които ще се пазят в музей, който се устройва в град Видин“. 
Дружеството развива активна дейност, но войните от 1912 до 1918 г. нарушават ритъма на неговата работа.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3a/Vidin-Konak-Museum1.JPG/675px-Vidin-Konak-Museum1.JPG',
'https://maps.app.goo.gl/eJVjS3hWuyocXwFq6'),
('Пещера Магура', 'с. Рабиша', 'Видин', 'Пещера', 'Магурата (от 1942 г. до 24 октомври 1972 г. официално Рабишка пещера), или нечленувано Магура, е пещера в Северозападна България, област Видин, община Белоградчик.
Известна е със своите рисунки (още от палеолита) от първобитни хора и многобройни прилепи.', 
'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4c/Magura_E7.jpg/1200px-Magura_E7.jpg',
'https://maps.app.goo.gl/GYn5xgMS2NQrZj2B6'),
('Белоградчишки скали', 'гр. Белоградчик', 'Видин', 'Скални форми', 'Белоградчѝшките скали са скални форми в Западния Предбалкан, в южното подножие на Белоградчишкия венец, около Белоградчик и селата Боровица, Чифлик и Праужда в област Видин и село Белотинци, област Монтана. 
Обявени са за природна забележителност през 1949 г.', 
'https://upload.wikimedia.org/wikipedia/commons/thumb/b/bb/%D0%A7%D0%B5%D1%80%D0%B2%D0%B5%D0%BD%D0%B8%D1%82%D0%B5_%D0%91%D0%B5%D0%BB%D0%BE%D0%B3%D1%80%D0%B0%D0%B4%D1%87%D0%B8%D1%88%D0%BA%D0%B8_%D1%81%D0%BA%D0%B0%D0%BB%D0%B8_-_%D0%91%D0%B5%D0%BB%D0%BE%D0%B3%D1%80%D0%B0%D0%B4%D1%87%D0%B8%D0%BA.jpg/1200px-%D0%A7%D0%B5%D1%80%D0%B2%D0%B5%D0%BD%D0%B8%D1%82%D0%B5_%D0%91%D0%B5%D0%BB%D0%BE%D0%B3%D1%80%D0%B0%D0%B4%D1%87%D0%B8%D1%88%D0%BA%D0%B8_%D1%81%D0%BA%D0%B0%D0%BB%D0%B8_-_%D0%91%D0%B5%D0%BB%D0%BE%D0%B3%D1%80%D0%B0%D0%B4%D1%87%D0%B8%D0%BA.jpg',
'https://maps.app.goo.gl/yBwwKeMhbz5q9Wez9'),
('Пещера Леденика', 'Враца', 'Враца', 'Пещера', 'Пещерата Леденика е разположена на 16 километра от град Враца, на територията на Природен парк „Врачански Балкан“. Намира се на 840 метра надморска височина в Стрешерския дял на Врачанската планина, в местността Леденишки увал.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8a/LedenikaCave.jpg/1280px-LedenikaCave.jpg', 'https://maps.app.goo.gl/4gdM8qe4yn47kq6w5'),
('Археологически комплекс „Калето“', 'Мездра', 'Враца', 'Археологически комплекс', 'Археологически комплекс „Калето“, съхраняващ 70-вековна история, се намира в югозападния край на Мездра, върху висок скалист рид, надвесен над левия бряг на река Искър.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/9/97/%D0%9C%D0%B0%D0%BA%D0%B5%D1%82_%D0%BA%D0%B0%D0%BB%D0%B5_1.JPG/1920px-%D0%9C%D0%B0%D0%BA%D0%B5%D1%82_%D0%BA%D0%B0%D0%BB%D0%B5_1.JPG',
'https://maps.app.goo.gl/oRMjMpahfXHsGupt9'),
('Национален музей „Параход Радецки“', 'Козлодуй', 'Враца', 'Музей', '„Радецки“ е бивш австро-унгарски пътнически параход (1851 – 1914/1924) и негова съвременна реплика (1966), използвана за кораб-музей.
Параходът „Радецки“ е паметен за българската история, тъй като е използван от четата на Христо Ботев за преминаване от Румъния в България.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8f/Radetzky_005.jpg/1280px-Radetzky_005.jpg', 'https://maps.app.goo.gl/QUSgKqUWrGhdi5K66'),
('Регионален етнографски музей на открито „Етър“', 'Габрово', 'Габрово', 'Музей', 'Регионален етнографски музей на открито „Етър“ е музей на открито, разположен в кв. Етъра в Габрово.
Представлява възстановка на българския бит, култура и занаятчийство. Той е първият по рода си музей в България. Открит е на 7 септември 1964 г. Музеят е разположен на 8 км южно от основната част на Габрово.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4c/Etura_Gabrovo_8.JPG/1280px-Etura_Gabrovo_8.JPG', 'https://maps.app.goo.gl/E2PW7PSKKdvAByfJ6'),
('Музей на образованието', 'Габрово', 'Габрово', 'Музей', 'Националния музей на образованието е музейна експозиция показваща етапите на българското образование от IX век до днес. Намира се в едно от крилата на Априловската гимназия в Габрово.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/5/59/Museum_of_Education%2C_Aprilovska_gimnasia.jpg/1280px-Museum_of_Education%2C_Aprilovska_gimnasia.jpg', 'https://maps.app.goo.gl/RTqcvouwysBHCyoQ6'),
('Дом на хумора и сатирата', 'Габрово', 'Габрово', 'Музей', 'Домът на хумора и сатирата е музей в Габрово с национално и световно значение. Сградата му се намира в централната част на града. Целта на музея е да популяризира хумора на народите в областта на изобразителното изкуство, 
литературата и фолклора, веселите празници и маскарадни традиции по света. Домът на хумора и сатирата има девиз: „Светът е оцелял, защото се е смял!“',
'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f9/Gabrovo_humor_Iz1.jpg/1280px-Gabrovo_humor_Iz1.jpg', 'https://maps.app.goo.gl/EAjA1UWJeFsHWzJQ6'),
('Регионален исторически музей, Дечкова къща', 'Габрово', 'Габрово', 'Музей', 'Регионалният исторически музей заема основно място в културния живот на града като създател на вече 135-годишната история на музейното дело в Габрово.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d0/Gabrovo_History_Museum_2013_01.JPG/1280px-Gabrovo_History_Museum_2013_01.JPG', 'https://maps.app.goo.gl/AFMtqi4ZhUM87Mcy9'),
('Музей в Архитектурно-исторически резерват', 'с. Боженците', 'Габрово', 'Музей', 'Боженците се намира на около 9 km източно от центъра на град Габрово и 6 km западно от град Трявна. Разположено е в южните разклонения на Габровските възвишения, 
в началото на долината на извиращата при селото и течаща на север река Андъ̀ка (наричана от местното население Божанка), заобиколено отвсякъде от височини и оттичащи се към селото долчини между тях.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/6/65/Bojentci-minkov.JPG/1200px-Bojentci-minkov.JPG', 'https://maps.app.goo.gl/E3fBhq8M23VDek81A'),
('Исторически музей Севлиево – Хаджистояново училище', 'Севлиево', 'Габрово', 'Музей', 'Внушителната сграда в центъра на града и днес носи името на своя дарител. Тя е построена през 1844 година за училищна сграда, която може да побере нарасналия брой желаещи да се учат севлиевски деца. 
Средствата за нея осигурява изцяло Хаджи Стоян Николов, градски първенец и богат търговец, който през 1825 г. е дарил средства и за построяване на килийно училище.',
'https://itc-sevlievo.com/wp-content/uploads/2017/03/46_110-768x512.jpg', 'https://maps.app.goo.gl/u2UZauAFNXCFeCdo9'),
('Ранновизантийска и средновековна крепост Хоталич', 'Севлиево', 'Габрово', 'Крепост', 'Хоталич е средновековен град-крепост на 4 км северозападно от град Севлиево. Разположен е над пролома на река Росица върху естествено укрепена хълмиста местност наречена Крушевски баир. Възникнал е 
през V-VІ век като военно укрепление, а през Х век е възстановен от българската държава, която започнала да изгражда укрепително съоръжение, с което да брани страната от нападения от север и от Византия на юг.',
'https://upload.wikimedia.org/wikipedia/commons/a/a7/%D0%A5%D1%80%D0%B0%D0%BC_%D0%B2_%D1%81%D1%80%D0%B5%D0%B4%D0%BD%D0%BE%D0%B2%D0%B5%D0%BA%D0%BE%D0%B2%D0%B5%D0%BD_%D0%B3%D1%80%D0%B0%D0%B4_%D0%A5%D0%BE%D1%82%D0%B0%D0%BB%D0%B8%D1%87_%D0%A1%D0%B5%D0%B2%D0%BB%D0%B8%D0%B5%D0%B2%D0%BE.jpg',
'https://maps.app.goo.gl/SFirrbg9BUvHmaf26'),
('Специализиран музей за резбарско и зографско изкуство', 'Трявна', 'Габрово', 'Музей', 'Музей „Ангел Кънчев“ е в сграда от началото на XIX век. В родния дом на Ангел Кънчев, помощник на Васил Левски, е представено участието на тревненци в националноосвободителните борби. Самата къща е красив образец на ранновъзрожденската архитектура.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/1/14/Daskalova.JPG/1280px-Daskalova.JPG', 'https://maps.app.goo.gl/P5wd5Fm9YL6Bwqt98'),
('Дряновски манастир', 'Дряново', 'Габрово', 'Манастир', 'Намира се в Северна България на 5 километра югозападно от град Дряново и на 15 километра от град Габрово. До него води асфалтов път. Обслужва се от железопътна спирка Бачо Киро, която до 20 октомври 1949 г. се казва Св. Архангел[1], на железопътната линия Русе-Момчилград. ЖП спирката 
се намира на около един километър от манастира, като е изградена горска пътека.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/9/9d/Dryanovo_TodorBozhinov_%280%29.JPG/1280px-Dryanovo_TodorBozhinov_%280%29.JPG', 'https://maps.app.goo.gl/qzuovkWsFANuvrMCA'),
('Пещера „Бачо Киро“', 'Дряново', 'Габрово', 'Пещера', 'Пещерата е разположена на 300 m западно от Дряновския манастир, на неголямо разстояние от водната пещера Андъка, в отвесна варовикова скала на 335 m н.в. За нейното опазване е обявена природната забележителност Бачо Киро.',
'https://upload.wikimedia.org/wikipedia/commons/2/2a/Bacho_Kiro_Cave.jpg', 'https://maps.app.goo.gl/ZzsBGWydsqpE3Cx4A'),
('Музей „Кольо Фичето“', 'Дряново', 'Габрово', 'Музей', 'Експозицията на историческия музей в град Дряново, посветена на живота и работата на Майстор Кольо Фичето, е открита през 1969 година по случай 170 години от рождението на Майстора. Никола Фичев е роден в град Дряново през 1800 година. Изучава дърводелство и зидария.',
'https://www.btsbg.org/sites/default/files/obekti/muzei-kolio-ficheto-drianovo.jpg', 'https://maps.app.goo.gl/5nJRZm9Sze8YDN6M6'),
('Дом-паметник „Йордан Йовков“', 'Добрич', 'Добрич', 'Музей', 'Открит е през 1980 г. във връзка със стогодишнината от рождението на класика на българската литература Йордан Йовков – един от най-известните ни писатели-хуманисти и майстор на разказа, чиито произведения са включени в много световни антологии и са преведени на над 40 езика.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/2/29/Museum_of_Yovkov_in_Dobrich.JPG/1280px-Museum_of_Yovkov_in_Dobrich.JPG', 'https://maps.app.goo.gl/qARq1JUj9znBT93b7'),
('Художествена галерия', 'Добрич', 'Добрич', 'Галерия', 'Художествена галерия - Добрич е един от най-големите музеи за изобразително изкуство, който предлага на ценители и посетители богата постоянна експозиция и наситен изложбен календар. Сградата е построена в духа на неокласицизма през 30-те години на ХХ век и е обявена за паметник на културата.',
'https://www.dobrich.bg/uploads/posts/2023/4b5161a9ae13b0c6e14e7ba60af4638e.jpg', 'https://maps.app.goo.gl/vJnaS3DkDkRZW1Xn8'),
('Архитектурно-парков комплекс „Двореца“', 'Балчик', 'Добрич', 'Архитектурно-парков комплекс', 'Архитектурно-парковият комплекс „Дворецът“ се намира на около 2 км югозападно от центъра на град Балчик, област Добрич. Представлява комплекс вили и други постройки, разположени на брега на Черно море. След възвръщането на Южна Добруджа през 1940 дворецът 
попада в границите на България и е разположен на площ от 194 дка.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6f/Bulgaria-Balchik-01.JPG/1200px-Bulgaria-Balchik-01.JPG', 'https://maps.app.goo.gl/FEjZ9KRC5bNjLCU68'),
('Университетска ботаническа градина', 'Балчик', 'Добрич', 'Ботаническа градина', 'Университетска ботаническа градина в Балчик е звено на Софийския университет „Св. Климент Охридски“.
Създадена е през 1955 г. Днес се простира на площ от 194 дка, като голяма част от територията ѝ е със статут на защитена местност по Закона на защитените територии.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/9/9b/Dobrich_Region_-_Balchik_Municipality_-_Town_of_Balchik_-_Balchik_Palace_and_Botanical_Garden_%281%29.jpg/1280px-Dobrich_Region_-_Balchik_Municipality_-_Town_of_Balchik_-_Balchik_Palace_and_Botanical_Garden_%281%29.jpg',
'https://maps.app.goo.gl/Sft2DNsqdxVT8XWm6'),
('Архитектурен резерват „Калиакра“ – нос Калиакра', 'Каварна', 'Добрич', 'Архитектурен резерват', 'Калиа̀кра (Геларе) е дълъг и тесен нос на българското северно черноморско крайбрежие, в югоизточната част на Добруджанското плато.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c9/Nos_Kaliakra.jpg/1280px-Nos_Kaliakra.jpg', 'https://maps.app.goo.gl/KXBJM65tG9TWF4i79'),
('Манастирски комплекс „Св. Йоан Предтеча“', 'Кърджали', 'Кърджали', 'Манастир', 'Кърджалийският манастир „Свети Йоан Предтеча“ е ранносредновековен български ансамбъл с крепостна стена и кули, с раннохристиянски корени и антично минало. След археологично изследване и разкопки през втората половина на ХХ век, през 90-те години на XX век са предприети 
възстановителни работи като от 2000 година реставрираната черква е осветена и в нея се извършва редовна служба.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/53/Saint_Joan-2.jpg/1280px-Saint_Joan-2.jpg', 'https://maps.app.goo.gl/bGUov2WaXUHfjZxH9'),
('Перперикон', 'Кърджали', 'Кърджали', 'Каменен комплекс', 'Перперѐк, наричан и Перперико̀н, е ранноисторически, античен и средновековен каменен комплекс в Източните Родопи, в територията на България, състоящ се от голямо мегалитно светилище от VI – V хилядолетие пр. Хр., паметници от античността и средновековна крепост. Смята се, че при траките, 
Перперек е свещен скален град, столица и крепост с царски дворец. По-късно тук са живели римляни, готи, ромеи и българи.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/3b/PerpericonCathedral.jpg/1280px-PerpericonCathedral.jpg', 'https://maps.app.goo.gl/qz2Qz8hC6AcKNUhs8'),
('Художествена галерия „Владимир Димитров – Майстора“', 'Кюстендил', 'Кюстендил', 'Галерия', 'На 6 август 1944 г. в кюстендилската джамия Ахмед бей по инициатива на Драган Лозенски, Кирил Цонев и д-р Георги Ефремов на основата на сбирка от 50 творби на Владимир Димитров – Майстора се открива музейна сбирка и художествена галерия.',
'https://upload.wikimedia.org/wikipedia/commons/9/96/VladimirDimitrovGallery.jpg', 'https://maps.app.goo.gl/zEPAq4Fqxsg1kZRHA'),
('Къща музей „Димитър Пешев“', 'Кюстендил', 'Кюстендил', 'Музей', 'Къща музей „Димитър Пешев“ е музейна историческа сбирка към Регионалния историческия музей в Кюстендил. Тя е паметник на културата. Възстановената къща на Димитър Пешев се намира на ул. „Цар Симеон I-ви“ № 11, в центъра на града, зад Художествената галерия „Владимир Димитров-Майстора“.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Dimitar_Peshev_house.1.jpg/1280px-Dimitar_Peshev_house.1.jpg', 'https://maps.app.goo.gl/JrJArNajtcLUSKvw7'),
('Музей „Средновековна църква Св. Георги“', 'Кюстендил', 'Кюстендил', 'Музей', '„Свети Георги Победоносец“ е средновековна българска църква в град Кюстендил. Църквата се намира в квартал Колуша в подножието на планината Осогово. Колуша е седалище на кюстендилския митрополит по времето на Османската империя.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b6/SvetiGeorgi.Kyustendil.1.jpg/1280px-SvetiGeorgi.Kyustendil.1.jpg', 'https://maps.app.goo.gl/DVqfmvM8odMPdwmP9'),
('Връх Руен', 'Осоговска планина', 'Кюстендил', 'Връх', 'Намира се в територията на област Кюстендил, България и община Крива паланка, Северна Македония.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/0/02/Ruen_IMG_4742.jpg/1280px-Ruen_IMG_4742.jpg',
'https://maps.app.goo.gl/SDYDcxnUvChD9dQt8'),
('Рилски манастир в Рилска света обител', 'Рилски манастир', 'Кюстендил', 'Манастир', 'Рилски манастир „Свети Йоан Рилски“ е ставропигиален манастир на Българската православна църква, сред най-значимите културни паметници в България, символ на страната, включен в Списъка на световното наследство на ЮНЕСКО.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b6/Rila_klooster.jpeg/1280px-Rila_klooster.jpeg', 'https://maps.app.goo.gl/37WsvMoQrVRvFrnZA'),
('Стобски пирамиди', 'с. Стоб', 'Кюстендил', 'Пирамиди', 'Стобските пирамиди са едни от най-популярните сред туристите скални пирамиди в България. Включени са в Червената книга на България като критично застрашено природно местообитание.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/7/72/Panorama_stobski_piramidi.jpg/1920px-Panorama_stobski_piramidi.jpg', 'https://maps.app.goo.gl/LHP49f7q5FWVwbLF6'),
('Седемте рилски езера', 'Рила', 'Кюстендил', 'Езера', 'Седемте рилски езера са група езера с ледников произход, разположена в планината Рила. Това е най-посещаваната от туристи езерна група в България и е един от стоте национални туристически обекта.', 
'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e7/Pogled_kum_ezerata_ot_biloto.JPG/1280px-Pogled_kum_ezerata_ot_biloto.JPG', 'https://maps.app.goo.gl/JyC7ftwvyXRTg1Y96'),
('Музей „Васил Левски“', 'Ловеч', 'Ловеч', 'Музей', 'Музеят „Васил Левски“ е част от Регионалния исторически музей в Ловеч. Той е посветен на Васил Левски, направил Ловеч център на Вътрешната революционна организация. Намира се в Архитектурно-историческия резерват „Вароша“, в който къщите са с характерна народна архитектура от възрожденската епоха.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/0/03/Museum_of_Vasil_Levski%2C_Lovech%2C_Bulgaria.jpg/1280px-Museum_of_Vasil_Levski%2C_Lovech%2C_Bulgaria.jpg',
'https://maps.app.goo.gl/t7ECXTwnwafnCeks8'),
('Къкринско ханче', 'с. Къкрина', 'Ловеч', 'Ханче', 'В него отсяда Васил Левски и е заловен от турски полицаи (заптиета) сутринта на 27 декември 1872 г. От съществуващите писмени документи е известно, че по внушение на Васил Левски ханчето в с. Къкрина е наето от Ловчанския частен революционен комитет. За ханджия е определен Христо Цонев–Латинеца, 
местен човек, преселен в Ловеч и съратник на Васил Левски.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/bd/Kakrina_han_E1.jpg/375px-Kakrina_han_E1.jpg', 'https://maps.app.goo.gl/11whaTDGWXNSmnRNA'),
('Етнографски музей', 'Ловеч', 'Ловеч', 'Музей', 'Започва съществуването си с откриване на експозиция в Драсовата къща през 1973 г. Тя е последвана от експозиция в съседната Рашова къща през 1983 г. Днес двете къщи оформят Етнографския комплекс на Ловеч.',
'https://lovech-museum.bg/wp-content/uploads/2015/05/etnografski1.jpg', 'https://maps.app.goo.gl/qGzDEdt6x2DzFuEWA'),
('Деветашка пещера', 'с. Деветаки', 'Ловеч', 'Пещера', 'Разположена е на около 7 km от Летница и на 15 km североизточно от Ловеч, близо до село Деветаки, на източния бряг на река Осъм. Достъпът до пещерата е по пътека, дълга над километър, която започва малко след отбивката от пътя Ловеч – гр. Левски за село Деветаки в източна посока, но при влажно време е затруднен.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7a/%D0%9A%D1%83%D1%80%D1%88%D1%83%D0%BD%D0%B0%2C%D0%94%D0%B5%D0%B2%D0%B5%D1%82%D0%B0%D1%88%D0%BA%D0%B0_%D0%BF%D0%B5%D1%89%D0%B5%D1%80%D0%B0_032.JPG/1280px-%D0%9A%D1%83%D1%80%D1%88%D1%83%D0%BD%D0%B0%2C%D0%94%D0%B5%D0%B2%D0%B5%D1%82%D0%B0%D1%88%D0%BA%D0%B0_%D0%BF%D0%B5%D1%89%D0%B5%D1%80%D0%B0_032.JPG',
'https://maps.app.goo.gl/RF2hhi3g8qVBUNti6'),
('Природна забележителност „Маарата“ – Крушунски водопади', 'с. Крушуна', 'Ловеч', 'Водопад', 'Крушу̀нски водопа̀ди (Крушунска бигорна каскада) – поредица от водопади в близост до село Крушуна, Община Летница, Област Ловеч, Северна България. Намират се на 8 км южно от град Летница, на 1 км южно от село Крушуна и са известни със своята живописност. Водопадите представляват дълга травертинова (бигорна) каскада, отделните стъпала на която са самите водопади.',
'https://upload.wikimedia.org/wikipedia/commons/7/78/KrushunaIwatterfall.jpg', 'https://maps.app.goo.gl/YVF3R1n1kj7ADXun7'),
('Национален пещерен дом', 'с. Карлуково', 'Ловеч', 'Пещерен дом', 'Националният пещерен дом - Карлуково, известен и като Национален пещерен дом "Петър Трантеев", е туристически обект в село Карлуково, България. Разположен е на ръба на отвесна скала в местността Калето, на десния бряг на река Искър, в непосредствена близост до пещера Проходна.
Проектът на сградата за Национален пещерен дом край Карлуково е разработен от архитекта на ЦС на БТС Кирил Масларски. Неговият иновативен подход се превръща в емблема за модерната архитектурна мисъл. Погледната от въздуха, сградата има форма на прилеп в полет.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/8/88/National_Spelunkers_Home.JPG/1280px-National_Spelunkers_Home.JPG', 'https://maps.app.goo.gl/13ppGnSnEZLtUeCb6'),
('Троянска Св. Обител „Успение Богородично“ – с. Орешак', 'с. Орешак', 'Ловеч', 'Манастир', 'Основан е около 1600 година (игумен Калистрат), възможно и преди това. Преданието говори за монаси от Атон, които отиват във Влашко със светинята на манастира – чудотворната икона на Богородица Троеручица, която е копие на старата чудотворна икона в Хилендарския манастир (XIV век). Троянският манастир бързо се разраства. Много скоро са издигнати дървена църква, 
посветена на Рождество Богородично, монашеско жилищно крило и малка гостоприемница. Не след дълго обаче, по времето на игумена Калистрий от Ловеч, манастирът е разгромен от турска банда. Самият игумен е посечен.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b4/Eglise_ste_vierge_trajan_monastere_2.jpg/800px-Eglise_ste_vierge_trajan_monastere_2.jpg',
'https://maps.app.goo.gl/kxvU4S71APhRbNQT6'),
('Музей на народните художествени занаяти и приложните изкуства', 'Троян', 'Ловеч', 'Музей', 'Началото на музейното дело в Троян е положено през 1924 г. от учителя краевед Власи Илиев Лингорски, автор и на първата история на града. Малката музейна сбирка в читалището, създадена по негова инициатива, е разположена между книгите в библиотеката.', 'https://www.btsbg.org/sites/default/files/obekti/muzei-na-prlojnite-izkustva-troyan.jpg',
'https://maps.app.goo.gl/n1XiKbeYM9PkJUmg6'),
('Пещера „Съева дупка“', 'с. Брестница', 'Ловеч', 'Пещера', 'Намира се на 3 километра южно от село Брестница, област Ловеч, на 10 км от Ябланица и на 25 км от Тетевен. Пещерата носи името на братя овчари Съю и Сейо, които я открили случайно и са я ползвали за укритие по време на османското владичество.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d0/Saeva_dupka.jpg/375px-Saeva_dupka.jpg', 'https://maps.app.goo.gl/8Mdm79qmHgGVu8mR6'),
('Къща музей „Иван Вазов“', 'Берковица', 'Монтана', 'Музей', 'Къща музей „Иван Вазов“ в Берковица е мястото, където Иван Вазов живее, докато е председател на Окръжния съд в Берковица – 7 март 1879 – 18 септември 1880 г. Къщата музей „Иван Вазов“ е част от Музейния комплекс в Берковица от 2012 г.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e0/Berkovitsa-IVHM.jpg/1280px-Berkovitsa-IVHM.jpg', 'https://maps.app.goo.gl/wjKbH9TC6aDofhUq6'), 
('Къща музей „Станислав Доспевски“', 'Пазарджик', 'Пазарджик', 'Музей', 'Къщата музей „Станислав Доспевски“ е единственият в България дом музей на възрожденски художник. Сградата е по проект на самия Станислав Доспевски и е построена от брациговски майстори през 1864 година. Тя е в характерен стил за епохата на Българското възраждане. На фронтона е изписано: „Притяжание Станислава Д. Доспесково - Самоковца, 1864“.', 
'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7d/Stanislav_Dospevski_House_Museum%2C_Pazardzhik%2C_Bulgaria.JPG/1280px-Stanislav_Dospevski_House_Museum%2C_Pazardzhik%2C_Bulgaria.JPG',
'https://maps.app.goo.gl/TvXZECZN4nB47rxJA'),
('Вилата музей „Александър Стамболийски“', 'с. Славовица', 'Пазарджик', 'Музей', 'Вилата музей „Александър Стамболийски“ се намира на 3 km източно от село Славовица, община Септември, област Пазарджик. Част е от 100 национални туристически обекта. Построена е през 1922 г. като вила на министър-председателя Александър Стамболийски върху собствен имот. Тя е на два етажа, а към нея има стара къща, стопанска сграда, навес и обор. На 14 юни 1923 г., след Деветоюнския преврат, Стамболийски е подложен на жестоки мъчения във вилата.', 
'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f1/Aleksandar_Stamboliyski_museum%2C_Slavovitsa%2C_Bulgaria_2019_14.jpg/1920px-Aleksandar_Stamboliyski_museum%2C_Slavovitsa%2C_Bulgaria_2019_14.jpg',
'https://maps.app.goo.gl/vzxvHKAParBZTMVXA'),
('Къща музей „Райна Княгиня“', 'Панагюрище', 'Пазарджик', 'Музей', 'Къщата музей „Райна Княгиня“ в Панагюрище е родната къща на Райна Княгиня. Обявена е за паметник на културата с национално значение, включена е сред Стоте национални туристически обекта на Българския туристически съюз. Построена през 1673 г., на 18 януари 1856 г. в къщата се ражда Райна Княгиня, а на 3 май 1950 г. отваря официално врати като къща музей.', 
'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6d/House-museumRaynaKnyaginya-Panagyurishte011.jpg/1920px-House-museumRaynaKnyaginya-Panagyurishte011.jpg', 'https://maps.app.goo.gl/D38yDfWk71rmoxf49'),
('Пещера „Снежанка“', 'Пещера', 'Пазарджик', 'Пещера', 'Разположена в Баташката планина в Родопите и се намира на 5 км от град Пещера. След отклонението от главния път от град Пещера към град Батак, има около 2 км тесен асфалтиран път, по който трудно се разминават два автомобила. По асфалтирания път се стига до паркинг, където може да оставите автомобила си. Пещерата е труднодостъпна (около 25 минути нагоре по стръмна екопътека с дължина 830 метра).',
'https://upload.wikimedia.org/wikipedia/commons/thumb/a/ae/Snejanka-Cave.jpg/1280px-Snejanka-Cave.jpg', 'https://maps.app.goo.gl/2Wr79qdpTM3kFGba6'),
('Средновековна крепост „Перистера“', 'Пещера', 'Пазарджик', 'Крепост', 'Крепостта Перистера се намира на север от град Пещера. Името на крепостта произхожда от гръцки и означава „гълъб“. Представлява крепост с три пояса крепостни стени и шест отбранителни кули, разположени на най-вътрешната крепостна стена, според археолозите е датирана към 4 век, като е съществувала поне до 7 век включително. Археолозите смятат, че на същото място вероятно е съществувало древно тракийско светилище.', 
'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a7/%D0%9F%D0%B5%D1%80%D0%B8%D1%81%D1%82%D0%B5%D1%80%D0%B0_%28%D0%BA%D1%80%D0%B5%D0%BF%D0%BE%D1%81%D1%82%29.jpg/1280px-%D0%9F%D0%B5%D1%80%D0%B8%D1%81%D1%82%D0%B5%D1%80%D0%B0_%28%D0%BA%D1%80%D0%B5%D0%BF%D0%BE%D1%81%D1%82%29.jpg',
'https://maps.app.goo.gl/EwkVYg32VdFo74Z26'),
('Музей на минното дело', 'Перник', 'Перник', 'Музей', 'Музеят на минното дело в Перник е създаден през 1986 г. Той е част от подземна минна галерия, в която между 1891 и 1966 г. са се добивали кафяви въглища. Музеят е единствен по рода си на Балканския полуостров.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7b/Mining_museums_of_Pernik_02.JPG/1280px-Mining_museums_of_Pernik_02.JPG',
'https://maps.app.goo.gl/k5rqQ3t8vSquEYLt7'),
('Античен театър', 'Пловдив', 'Пловдив', 'Театър', 'Античният театър на Филипополис е сред най-добре запазените антични театри в света и сред основните туристически атракции на Пловдив. Построен е по времето на римския император Марк Улпий Траян (98 – 117) сл. Хр. и е разкрит при археологически разкопки от 1968 до 1979 г. от Археологически музей Пловдив. Разположен е между Джамбаз тепе и Таксим тепе. Театърът на Филипопол e единствената запазена антична театрална сграда по българските земи.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/0/0c/Bulgaria_Bulgaria-0785_-_Roman_Theatre_of_Philippopolis_%287432772486%29.jpg/1280px-Bulgaria_Bulgaria-0785_-_Roman_Theatre_of_Philippopolis_%287432772486%29.jpg',
'https://maps.app.goo.gl/Ky5SAmPDgZsLthaM7'),
('Римски стадион', 'Пловдив', 'Пловдив', 'Площад', 'Площад „Римски стадион“ в Пловдив е известен с името „Джумаята“, което никога не е било негово официално наименование. Предишните му имена са „Айнал мегдан“ (Лунен площад), „Александър Стамболийски“, „Княз Борис“ и „19 ноември“. Победата при Сливница e на 19 ноември 1885 г. ключова дата в българската история, но съседната Джумая джамия е винаги била ориентир на пловдивчани и налага неофициално името си. Думата „джумая“ в арабския език означава петък или празник. Централното му място определя площада като „пъпа“ на Пловдив.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b5/Plovdiv_-_Bulgarien_019.JPG/1280px-Plovdiv_-_Bulgarien_019.JPG', 'https://maps.app.goo.gl/8YetgZpEpZKy4LMEA'),
('Епископска базилика на Филипопол', 'Пловдив', 'Пловдив', 'Епископската базилика', 'Епископската базилика на Филипопол, наричана още Голяма базилика, e раннохристиянски храм в Пловдив. Датира от средата на IV в.сл.Хр., като е функционирала в периода IV – VI в., когато вероятно е била епископската катедрала на града. Тя е най-големият раннохристиянски храм, открит на територията на България и един от най-големите на Балканския полуостров.', 
'https://upload.wikimedia.org/wikipedia/commons/thumb/7/71/Bishop_bas_15.jpg/1280px-Bishop_bas_15.jpg', 'https://maps.app.goo.gl/Xh7WvmHryVLi1cTb8'),
('Женски метох „Въведение Богородично“', 'Сопот', 'Пловдив', 'Манастир', 'Сопотският манастир „Въведение Богородично“ е български православен девически манастир в Пловдивската епархия на Българската православна църква.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f4/%D0%94%D0%B5%D0%B2%D0%B8%D1%87%D0%B5%D1%81%D0%BA%D0%B8_%D0%BC%D0%B0%D0%BD%D0%B0%D1%81%D1%82%D0%B8%D1%80%2C_%D0%A1%D0%BE%D0%BF%D0%BE%D1%82_%28706725315%29.jpg/1280px-%D0%94%D0%B5%D0%B2%D0%B8%D1%87%D0%B5%D1%81%D0%BA%D0%B8_%D0%BC%D0%B0%D0%BD%D0%B0%D1%81%D1%82%D0%B8%D1%80%2C_%D0%A1%D0%BE%D0%BF%D0%BE%D1%82_%28706725315%29.jpg',
'https://maps.app.goo.gl/egzpEq8vi2AJtYeY6'),
('Национален музей „Васил Левски“', 'Карлово', 'Пловдив', 'Музей', 'Националният музей „Васил Левски“ в Карлово е посветен на българския национален герой Васил Левски. Обхваща родната му къща, експозиционна зала, мемориален параклис „Всех святих болгарских“, Чардаклиевата къща и Онбашиевата къща.', 
'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b1/%D0%9D%D0%B0%D1%86%D0%B8%D0%BE%D0%BD%D0%B0%D0%BB%D0%B5%D0%BD_%D0%BC%D1%83%D0%B7%D0%B5%D0%B9_%E2%80%9E%D0%92%D0%B0%D1%81%D0%B8%D0%BB_%D0%9B%D0%B5%D0%B2%D1%81%D0%BA%D0%B8%E2%80%9D%2C_%D1%81%D0%B3%D1%80%D0%B0%D0%B4%D0%B0.jpg/1280px-%D0%9D%D0%B0%D1%86%D0%B8%D0%BE%D0%BD%D0%B0%D0%BB%D0%B5%D0%BD_%D0%BC%D1%83%D0%B7%D0%B5%D0%B9_%E2%80%9E%D0%92%D0%B0%D1%81%D0%B8%D0%BB_%D0%9B%D0%B5%D0%B2%D1%81%D0%BA%D0%B8%E2%80%9D%2C_%D1%81%D0%B3%D1%80%D0%B0%D0%B4%D0%B0.jpg',
'https://maps.app.goo.gl/w7bv3rdtT41NUGNP7'),
('Връх Кадрафил – гроба на Хаджи Димитър', 'с. Свежен', 'Пловдив', 'Връх', 'Кадрафил (или Къдрафил) е връх с височина 882 m в Сърнена Средна гора. Намира се между селата Свежен и Мраченик. Според някои изследвания, там е починал Хаджи Димитър.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8b/The_Tomb_of_Dimiter_Asenov.jpg/1280px-The_Tomb_of_Dimiter_Asenov.jpg', 'https://maps.app.goo.gl/dTEFbg3Bj3vyaPvCA'),
('Национален музей „Христо Ботев“', 'Калофер', 'Пловдив', 'Музей', 'Националният музей „Христо Ботев“ се намира в Калофер – родния град на големия български поет и революционер. Разположен е в парк „Ботевата градина“ и включва следните обекти: мемориална къща музей, изложбена зала, паметник на Христо Ботев и паметник на Иванка Ботева – майка на поета.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/5/50/Botev_House.jpg/1280px-Botev_House.jpg', 'https://maps.app.goo.gl/XYiUFxr4wiWRD7hj8'),
('Водопад „Райското пръскало“', 'Калофер', 'Пловдив', 'Водопад', 'Райското пръскало е водопад в България с височина от 124,5 м. Намира се в Стара планина, на южния склон под най-високия старопланински връх – Ботев. На територията е на природен резерват „Джендема“, част от Национален парк „Централен Балкан“. Обявен е за защитен природен обект през 1965 г.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/0/08/%D0%A0%D0%B0%D0%B9%D1%81%D0%BA%D0%BE%D1%82%D0%BE_%D0%BF%D1%80%D1%8A%D1%81%D0%BA%D0%B0%D0%BB%D0%BE_%D0%91%D0%B0%D0%BB%D0%BA%D0%B0%D0%BD.jpg/1280px-%D0%A0%D0%B0%D0%B9%D1%81%D0%BA%D0%BE%D1%82%D0%BE_%D0%BF%D1%80%D1%8A%D1%81%D0%BA%D0%B0%D0%BB%D0%BE_%D0%91%D0%B0%D0%BB%D0%BA%D0%B0%D0%BD.jpg',
'https://maps.app.goo.gl/1FWNqk5V5WPYtPVy9'), 
('Асенова крепост', 'Асеновград', 'Пловдив', 'Крепост', 'Асеновата крепост е средновековна крепост с укрепената църква „Света Богородица Петричка“. Намира се в планината Родопи на 2 km от Асеновград, България. Крепостта е съществувала още по времето на траките, преустроена е от Византия през IX век, за да охранява вратата на Беломорския проход и да осигури византийската граница в този край.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/d/da/Church_of_the_Holy_Mother_of_God%2C_Asen%27s_Fortress%2C_Bulgaria_07.JPG/1280px-Church_of_the_Holy_Mother_of_God%2C_Asen%27s_Fortress%2C_Bulgaria_07.JPG',
'https://maps.app.goo.gl/dh6jK2mAvfjX7X8X7'),
('Бачковски манастир', 'Бачково', 'Пловдив', 'Манастир', 'Бачковският манастир „Успение Богородично“ е ставропигиален манастир край село Бачково, община Асеновград, област Пловдив. Той е вторият по големина български манастир след Рилския.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/8/80/Monastere_batchkovo.jpg/1280px-Monastere_batchkovo.jpg', 'https://maps.app.goo.gl/LmQCEdh7uY7g3DCK8'),
('Къща музей „Захарий Стоянов“', 'Русе', 'Русе', 'Музей', 'Къщата музей „Захари Стоянов“ се намира в Русе. В нея са представени експозиции за Българското Възраждане, църковно-просветните и националноосвободителните борби в Русенския край, за семейство Обретенови - семейството на Баба Тонка, както и за живота и делото на летописеца на Априлското въстание Захарий Стоянов.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/7/7c/Zaharii_Stoianov_hause.jpg/1280px-Zaharii_Stoianov_hause.jpg', 'https://maps.app.goo.gl/SDhjNZCCnTNcx6rm9'),
('Скален Манастир „Свети Димитрий Басарбовски“', 'с. Басарбово', 'Русе', 'Манастир', 'Басарбовският манастир „Свети Димитър Басарбовски“ е скален манастир в България. Обителта е един от двата действащи скални манастира в България (заедно с Разбоишки манастир), като храмът е отворен за посетители всекидневно.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/7/73/BG_Basarbovo_rock_monastery_12.jpg/1280px-BG_Basarbovo_rock_monastery_12.jpg', 'https://maps.app.goo.gl/tuRVim3BUpyuG2Bx8'),
('Природонаучен музей при биосферен резерват „Сребърна“', 'с. Сребърна', 'Силистра', 'Музей', '„Сребърна“ е биосферен резерват в България, включен в Списъка на световното културно и природно наследство на ЮНЕСКО. Местността е обявена за резерват през 1948 г. Охраняемата площ е от около 892,05 ha, буферната зона от около 540 ha.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/a/ae/Dalmatian_Pelican_and_Great_Cormorant_in_danube_delta.jpg/1920px-Dalmatian_Pelican_and_Great_Cormorant_in_danube_delta.jpg',
'https://maps.app.goo.gl/uDigv7KqSxoNgRP28'),
('Етнографски музей „Дунавски риболов и лодкостроене“', 'Тутракан', 'Силистра', 'Музей', 'Музеят е открит през 1974 г. и е единствен в страните по поречието на река Дунав. Създаден е, за да съхрани богатата материална и духовна култура, обществено устройство и бит на българите от крайдунавските рибарски селища. Неслучайно музеят се намира в Тутракан, защото риболовът е основен поминък на населението в този край от древността до днес. В края на ХІХ и началото на ХХ век градът се утвърждава като център на дунавския риболов.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/4/43/%D0%9C%D1%83%D0%B7%D0%B5%D0%B9_%E2%80%9E%D0%94%D1%83%D0%BD%D0%B0%D0%B2%D1%81%D0%BA%D0%B8_%D1%80%D0%B8%D0%B1%D0%BE%D0%BB%D0%BE%D0%B2_%D0%B8_%D0%BB%D0%BE%D0%B4%D0%BA%D0%BE%D1%81%D1%82%D1%80%D0%BE%D0%B5%D0%BD%D0%B5%E2%80%9C_01.jpg/1280px-%D0%9C%D1%83%D0%B7%D0%B5%D0%B9_%E2%80%9E%D0%94%D1%83%D0%BD%D0%B0%D0%B2%D1%81%D0%BA%D0%B8_%D1%80%D0%B8%D0%B1%D0%BE%D0%BB%D0%BE%D0%B2_%D0%B8_%D0%BB%D0%BE%D0%B4%D0%BA%D0%BE%D1%81%D1%82%D1%80%D0%BE%D0%B5%D0%BD%D0%B5%E2%80%9C_01.jpg',
'https://maps.app.goo.gl/NMJUxzqkfMV6DJRS6'),
('Национален музей на текстилната индустрия', 'Сливен', 'Сливен', 'Музей', 'Музеят на текстилната индустрия е специализиран музей, който съхранява и представя културни ценности, свързани с българското текстилно индустриално културно наследство, с историята и развитието на текстилната техника и технология и ролята на Сливен в стопанското развитие на страната ни.',
'https://textile-museum.com/uploads/thumbs/%D0%B8%D1%81%D1%82%D0%BE%D1%80%D0%B8%D1%8F_1.jpg', 'https://maps.app.goo.gl/MwTE9KJ7kSotFAP89'),
('Художествена галерия „Димитър Добрович“', 'Сливен', 'Сливен', 'Галерия', 'сновите на Художествена галерия „Димитър Добрович“ са поставени през далечната 1905 г. – със завещанието на възрожденския живописец  Димитър Добрович. Със завещаните творби младият художник Йордан Кювлиев урежда постоянна експозиция в библиотеката на местното читалище „Зора“. По-късно след  неочакваната му  смърт  неговата майка Зоица  дарява на институцията четиридесетина негови платна.',
'https://static.gallerysliven.com/uploads/2018/08/Istoricheski-muzei.jpg', 'https://maps.app.goo.gl/XDKwWWrACtQ9pPzr9'),
('Къща-музей "Сливенски бит"', 'Сливен', 'Сливен', 'Музей', 'През първата четвърт на ХІХ век, неизвестни тревненски майстори построяват в една от най-старите махали на Сливен - Кафтанджийската, отворена симетрична чардаклиена къща. Тя е образец на жилищната архитектура от годините на Възраждането. Собственикът й, търговецът на аби и шаяци дядо Бою, в действителност построява две къщи, залепени една за друга. По-голямата, която е построена най-напред, е известна като къщата на Паткоолу, а по-малката и по-късна, като Арнауткината.',
'https://museum.sliven.net/uploads/CF82B8F78D243F69C1A77E17674BD830.jpg', 'https://maps.app.goo.gl/zEtETYMjxooDW8ik6'),
('Природонаучен музей', 'Котел', 'Сливен', 'Музей', 'Природонаучният музей в Котел е един от най-богатите в България. В него се разкрива биоразнообразието на Източна Стара планина, чрез близо 30 000 експоната от живата и неживата природа, разположени на площ от 1000 m2.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/6/60/Kotel_Natural_History_museum.JPG/800px-Kotel_Natural_History_museum.JPG', 'https://maps.app.goo.gl/EXn6BYJFwCf6T2xa8'),
('Къща музей „Йордан Йовков“', 'с. Жеравна', 'Сливен', 'Музей', 'Уредена е в родната къща на големия български писател. В ниската дъбова постройка тип „приземна камчийска жеравненска къща” в махала „Голямо бърдо” са представени лични и семейни предмети на Йордан Йовков, фотодокументи, ръкописи и оригинални първи издания от богатото творческо наследство на писателя.',
'https://muzeum-kotel.com/images/11_2_b.jpg', 'https://maps.app.goo.gl/7mySX11tMxNuuhV58'),
('Национален исторически музей', 'София', 'София-град', 'Музей', 'НИМ е създаден с разпореждане на Бюрото на Министерския съвет на НРБ през 1973 г. Първата експозиция е открита през 1984 г. в сградата на Съдебната палата в София в чест на 1300-годишнината от създаването на българската държава.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/7/79/Bulgarian_National_Museum_of_History.jpg/1280px-Bulgarian_National_Museum_of_History.jpg', 'https://maps.app.goo.gl/x4VQwd9JiHBNKUJD6'),
('Национален музей „Боянска черква“', 'София', 'София-град', 'Музей', 'Боянската църква „Св. св. Никола и Пантелеймон“ е средновековна българска църква (придворен параклис, по-късно манастир) в софийския квартал Бояна, намиращ се в подножието на Витоша. Тя е един от културните символи на България и е включена през 1979 г. като културен паметник в Списъка на световното културно и природно наследство на ЮНЕСКО под № 42. Филиал е на Националния исторически музей от 2003 г.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/3/37/Boyana_Church_1.jpg/1280px-Boyana_Church_1.jpg', 'https://maps.app.goo.gl/KkZKRv3SdJKcCvCX9'),
('Храм-паметник „Свети Александър Невски“ с криптата', 'София', 'София-град', 'Храм-паметник', '„Свети Александър Невски“ е православен храм-паметник в град София, България, катедрален храм на българския патриарх. Разположена е на площад със същото име. Църквата е проектирана и изградена в периода 1882 – 1912 г.,а и през 1955 г. е обявена за паметник на културата с национално значение. Включена е в списъка на 100-те национални туристически обекта на БТС.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e7/Cathedral_Saint_Alexander_Nevsky_%2823997180108%29.jpg/500px-Cathedral_Saint_Alexander_Nevsky_%2823997180108%29.jpg',
'https://maps.app.goo.gl/5E2mNBunwGqYgJru5'),
('Национален военноисторически музей', 'София', 'София-град', 'Музей', 'Националният военноисторически музей в София (съкратено НВИМ) е военен, научноизследователски и културно-просветен институт, административно подчинен на Министерството на отбраната. Музеят има статут на национална институция на България.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4a/National_Museum_of_Military_History.jpg/500px-National_Museum_of_Military_History.jpg', 'https://maps.app.goo.gl/2ThT3a1XtbCd5Bsg8'),
('Национален дворец на културата', 'София', 'София-град', 'Културен център ', 'Националният дворец на културата, съкратено НДК (с наименование до 1990 г.: Народен дворец на културата „Людмила Живкова“ ), е национален културен център в София за конференции, изложби и специални събития, най-големият конгресен център в Югоизточна Европа.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/e/ec/National_Palace_of_Culture_%2823997858848%29.jpg/500px-National_Palace_of_Culture_%2823997858848%29.jpg',
'https://maps.app.goo.gl/BjrX1n43WApUu31f8'),
('Етнографски институт с музей при БАН', 'София', 'София-град', 'Институтът за етнология и фолклористика с етнографски музей', 'Разположен е в сградата на бившия Царски дворец, която дели с Националната галерия. Сградата е обявена за паметник на културата от национално значение през 1978 г. От настаняването му (1954) музеят се помещава в източното крило на двореца, където са били спалните, приемните и личните кабинети на царското семейство.',
'https://upload.wikimedia.org/wikipedia/commons/4/46/National_Art_Gallery%2C_Bulgaria_%28by_Pudelek%29.JPG', 'https://maps.app.goo.gl/AmatZy2SzgCqysAf9'),
('Национална художествена галерия', 'София', 'София-град', 'Национална галерия', 'Намира се в центъра на София. Помещава се в централния корпус и в северозападното крило на бившия Царски дворец, като ползва общ вход с Националния етнографски музей (настанен в югоизточното крило). Носи сегашното си име от 2015 г.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/9/97/National_Ethnographic_Museum%2C_Sofia%2C_Bulgaria.jpg/1280px-National_Ethnographic_Museum%2C_Sofia%2C_Bulgaria.jpg', 'https://maps.app.goo.gl/pT5FrYz4j17g4dXK7'),
('Зоологическа градина от 1888 г.', 'София', 'София-град', 'Зоологическа градина', ' Понастоящем в софийската зоологическа градина се отглеждат голям брой екзотични животни, както и много животни, които са характерни за българските земи. На площ от 360 декара в зоопарка живеят 237 различни вида, от които 29 са застрашени видове, като общият брой на индивидите е повече от 2150.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/c/c7/EntranceSofiaZoo.JPG/500px-EntranceSofiaZoo.JPG', 'https://maps.app.goo.gl/izoDAyxGA9gEojDo9'),
('Златноливаденски манастир', 'Чирпан', 'Стара Загора', 'Манастир', 'Златноливаденският или Чирпанският манастир „Свети Атанасий“ е женски православен манастир в Южна България. Манастирът се намира близо до село Златна ливада. Разположен е на хълм над селото, на десния бряг на Стара река, недалеч от вливането ѝ в река Марица, на 14 км от град Чирпан и на 53 км южно от Стара Загора.', 
'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f2/Monastery_of_Saint_Athanasius_Iz4.jpg/375px-Monastery_of_Saint_Athanasius_Iz4.jpg', 'https://maps.app.goo.gl/gjxnczmFHLDyQbx56'),
('Тракийска куполна гробница', 'с. Мезек', 'Хасково', 'Гробница', 'Мезешката гробница е тракийска куполна гробница от микенски тип датирана от 4 – 3 в. пр. Хр. Намира се в покрайнините на село Мезек, община Свиленград, в могилата „Мелтепе“. Това е една от най-големите тракийски гробници в България.', 
'https://upload.wikimedia.org/wikipedia/commons/thumb/0/05/TrakiGrobnica.JPG/1280px-TrakiGrobnica.JPG', 'https://maps.app.goo.gl/3CkCqsggozJaD5mH9'),
('Дом-музей „Пеньо Пенев“', 'Димитровград', 'Хасково', 'Музей', 'Домът музей „Пеньо Пенев“ е филиал на Историческия музей в Димитровград. Посветен е на живота и творчеството на поета Пеньо Пенев.', 
'https://th.bing.com/th/id/OIP.vCujOvBdsaRmX7aPZq9yvAHaFj?rs=1&pid=ImgDetMain', 'https://maps.app.goo.gl/rveEWwzzL19WL2WX7'),
('Паметник „Създатели на българската държава“', 'Шумен', 'Шумен', 'Паметник', '„Създателите на българската държава“, известен също като „1300 години България“, е архитектурен комплекс, посветен на 1300-годишнината от създаването на българската държава. Монументът е разположен в най-високата част на Дунавската равнина – Шуменското плато – на 450 метра надморска височина и се извисява над град Шумен. Открит е през ноември 1981 г.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/6/6d/Choumen_-_Monument_1300_ans.jpg/375px-Choumen_-_Monument_1300_ans.jpg', 'https://maps.app.goo.gl/AjXwmQD6uhLrAN6T9'),
('Томбул джамия „Шериф Халил паша – 1744 г.“', 'Шумен', 'Шумен', 'Джамия', 'Шериф Халил паша джамия, известна повече като Томбул джамия (на турски: Tombul Camii) е мюсюлмански храм, който в миналото е бил разположен в централна част на град Шумен. Впоследствие, с изместването на централната градска част, джамията остава в югозападната част на града. Името на сградата „томбул“ идва от формата на купола.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/9/93/Tombul-Moschee-Ostfassade1.jpg/1280px-Tombul-Moschee-Ostfassade1.jpg', 'https://maps.app.goo.gl/hXajUqn71WnLrQp98'),
('Мадарския конник', 'с. Мадара', 'Шумен', 'Резервата', 'Ма̀дара е название на историко-археологическия резерват, който обхваща няколкостотин декара площ, която от 2006 година трябва да бъде и защитена територия. Намира се в Североизточна България. Центърът на резервата е около Голямата пещера - скален навес с височина около 30 метра, и намиращата се в близост Малка пещера. И двете природни образувания са давали подслон на най-древното население на Балканите.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Reserva_hist%C3%B3rico-arqueol%C3%B3gica_Nacional_de_Madara%2C_Bulgaria%2C_2016-05-27%2C_DD_57.jpg/330px-Reserva_hist%C3%B3rico-arqueol%C3%B3gica_Nacional_de_Madara%2C_Bulgaria%2C_2016-05-27%2C_DD_57.jpg',
'https://maps.app.goo.gl/KtvzZ5DiLA4tuQ2b7'),
('Ямболски безистен', 'Ямбол', 'Ямбол', 'Безистен', 'Ямболският безистен е търговски обект (покрит пазар) и културно-исторически паметник в Ямбол, България. Заедно с Шуменския са единствените безистени в България, запазени от времето на османското владичество. Нареждан е сред най-красивите покрити пазари на Балканите, оценяван е като еталон на общественото строителство за граждански нужди в Османската империя в периода ХV – ХVІІ век.',
'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4c/%D0%AF%D0%BC%D0%B1%D0%BE%D0%BB_%D0%91%D0%B5%D0%B7%D0%B8%D1%81%D1%82%D0%B5%D0%BD%D0%B0_4.jpg/1920px-%D0%AF%D0%BC%D0%B1%D0%BE%D0%BB_%D0%91%D0%B5%D0%B7%D0%B8%D1%81%D1%82%D0%B5%D0%BD%D0%B0_4.jpg',
'https://maps.app.goo.gl/KLUj2ek2PiF5Ea8Z8'),
('Музей на бойната слава', 'Ямбол', 'Ямбол', 'Музей', 'Музеят на бойната слава е културна институция в град Ямбол и е първият общински специализиран военен музей в България. Създаването му е по идея на инициативен комитет и родолюбивите дружества и организации в града, подкрепени от кмета на община Ямбол, Георги Славов. С решение на Общинския съвет от 28 юли 2010 г. е избран бивш войскови район, известен като „Пионерните казарми“, място, където е била разположена 3-та пионерна дружина.', 
'https://kmeta.bg/wp-content/uploads/2021/03/52a16802a86b3.jpg', 'https://maps.app.goo.gl/Hz1YgPay8tPTfdj89');

select * from list_landmarks;

create table landmark_images (
    image_id int auto_increment primary key,
    landmark_id int not null,
    image_url varchar(855) not null,
    foreign key (landmark_id) references list_landmarks(id) on delete cascade
);